package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithCommentMarker() {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        Character commentMarker = '#';

        // When
        CSVFormat result = csvFormat.withCommentMarker(commentMarker);

        // Then
        assertEquals(commentMarker, result.getCommentMarker());
    }

    @Test
    public void testWithCommentMarker_lineBreak() {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        Character lineBreak = '\n';

        // When
        IllegalArgumentException exception = assertThrows(IllegalArgumentException.class,
                () -> csvFormat.withCommentMarker(lineBreak));

        // Then
        assertEquals("The comment start marker character cannot be a line break", exception.getMessage());
    }

    @Test
    public void testWithCommentMarker_null() {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        IllegalArgumentException exception = assertThrows(IllegalArgumentException.class,
                () -> csvFormat.withCommentMarker(null));

        // Then
        assertEquals("The comment start marker character cannot be null", exception.getMessage());
    }

    @Test
    public void testWithCommentMarker_otherCharacter() {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        Character otherCharacter = '@';

        // When
        CSVFormat result = csvFormat.withCommentMarker(otherCharacter);

        // Then
        assertEquals(otherCharacter, result.getCommentMarker());
    }

}
